class Probe:
	"""
	Probe description
	"""
	def __init__(self, ownerComp):
		self.ownerComp = ownerComp

	def computeMetric(self, dataop, datatype):

		findop = op('opfind')
		val = 0.

		if (op('instance')[0] > -1 or findop.numRows>1) :
			try:
				name = dataop.name

				# make sure the cook times have occcured recently
				if datatype == 'cputime' :
					val = dataop.cookTime * int((absTime.frame-dataop.cookAbsFrame)<6)  \
						+ dataop.childrenCPUCookTime * int((absTime.frame-dataop.childrenCookAbsFrame)<6)
				elif datatype == 'gputime' :
					val = dataop.gpuCookTime * int((absTime.frame-dataop.cookAbsFrame)<6)   \
						+ dataop.childrenGPUCookTime * int((absTime.frame-dataop.childrenGPUCookAbsFrame)<6)
				elif datatype == 'cpumemory' :
					val = (dataop.cpuMemory + dataop.childrenCPUMemory()) / 1000000.
				elif datatype == 'gpumemory' :
					val = (dataop.gpuMemory + dataop.childrenGPUMemory()) / 1000000.
				elif datatype == 'children' :
					val = len(dataop.findChildren()) if dataop.isCOMP else 0
			except:
				pass

		return val

