*����������������� $"""
Extension classes enhance TouchDesigner components with python. An
extension is accessed via ext.ExtensionClassName from any operator
within the extended component. If the extension is promoted via its
Promote Extension parameter, all its attributes with capitalized names
can be accessed externally, e.g. op('yourComp').PromotedFunction().

Help: search "Extensions" in wiki
"""

from TDStoreTools import StorageManager
TDF = op.TDModules.mod.TDFunctions

class NavBarExt:
	"""
	NavBarExt description
	"""
	def __init__(self, ownerComp):
		# The component to which this extension is attached
		self.ownerComp = ownerComp
		self.timer = 0
		self.historyDat = self.ownerComp.op('history')

	def clearHistory(self):
		self.historyDat.clear()
		self.historyDat.appendRow(['path', 'step'])

	def handleParVal(self, par, prev):
		if par.name == 'Path':
			self.setHistory(par.val)

	def handleParPulse(self, par):
		if par.name == 'Home':
			self.goHome()
		elif par.name == 'Clear':
			self.clearHistory()
		elif par.name == 'Viewhistory':
			self.historyDat.openViewer()

	def incrTimer(self, panelValue):
		self.timer = self.timer+1
		if self.timer > 60:
			if panelValue.owner.parent.Widget.name == 'back':
				debug('back with history')
			else:
				debug('forward with history')
			self.timer = 0
			panelValue.val = False

	def goBack(self):
		"""
		Navigates backward in the history list
		"""
		if self.timer < 60:
			self.timer = 0
			self.setStep(-1)

	def goForward(self):
		"""
		Navigates forward in the history list
		"""
		if self.timer < 60:
			self.timer = 0
			self.setStep(1)

	def goHome(self):
		"""
		Navigates to the root
		"""
		self.ownerComp.par.Path = '/'

	def setHistory(self, path):
		"""
		Sets the new path history.  If its the same path it assumes the
		request has come from a race condition from the path parameter update
		via script
		"""
		if self.historyDat.numRows > 1:
			curPath = self.historyDat[self.curStep+1, 0].val
		else:
			curPath = False
		if path != curPath:
			self.historyDat.appendRow([path, False])
			self.setStep(0)

	@property
	def curStepList(self):
		"""
		returns the current step list from the history list
		"""
		return [eval(i.val) for i in self.historyDat.col(1)[1:]]

	@property
	def curStep(self):
		"""
		Returns the current step index from the history table
		"""
		#debug(self.historyDat.numRows)
		trues = [i for i, x in enumerate(self.curStepList) if x]
		if trues:
			curStep = trues[0]
		elif self.historyDat.numRows == 1:
			curStep = 0
		else:
			curStep = len-1
		return curStep

	def setStep(self, dir):
		"""
		Sets the step location in the history list
		"""
		len = self.historyDat.numRows-1
		if dir == 0:
			index = len-1
		else:
			curIndex = self.curStep
			if dir == 1:
				if curIndex < len-1:
					index = curIndex+1
				else:
					index = curIndex
			elif dir == -1:
				index = max(0 ,curIndex-1)
		stepList = [False]*len
		#debug('stepList', stepList)
		if stepList:
			stepList[index] = True
			self.historyDat.replaceCol(1, ['step'] + stepList)
			self.ownerComp.par.Path = self.historyDat[self.curStep+1, 0].val

